# search for mentions of jubb or yusuf or 'غيابة'
def extract_matn(record):
    # keys 'hadithTxt' or 'Matn' exist; choose whichever present
    if 'hadithTxt' in record and record['hadithTxt']:
        return record['hadithTxt']
    if 'Matn' in record and record['Matn']:
        return record['Matn']
    return None

def search_hadith(keyword):
    nkey = normalize(keyword)
    res = []
    for rec in hadith_data:
        txt = extract_matn(rec)
        if not txt:
            continue
        if normalize(txt).find(nkey) != -1:
            res.append(txt)
            if len(res) >= 5:
                break
    return res

